--
-- Structure for view `v_visit_summaries`
--
DROP TABLE IF EXISTS `v_visit_summaries`;

CREATE ALGORITHM=UNDEFINED DEFINER=`u524585165_lifecare`@`127.0.0.1` SQL SECURITY DEFINER VIEW `v_visit_summaries`  AS SELECT lcase(concat(hex(substr(`tx`.`tx_id`,1,4)),'-',hex(substr(`tx`.`tx_id`,5,2)),'-',hex(substr(`tx`.`tx_id`,7,2)),'-',hex(substr(`tx`.`tx_id`,9,2)),'-',hex(substr(`tx`.`tx_id`,11)))) AS `visit_id`, lcase(concat(hex(substr(`tx`.`wallet_id`,1,4)),'-',hex(substr(`tx`.`wallet_id`,5,2)),'-',hex(substr(`tx`.`wallet_id`,7,2)),'-',hex(substr(`tx`.`wallet_id`,9,2)),'-',hex(substr(`tx`.`wallet_id`,11)))) AS `wallet_id`, lcase(concat(hex(substr(`tx`.`beneficiary_id`,1,4)),'-',hex(substr(`tx`.`beneficiary_id`,5,2)),'-',hex(substr(`tx`.`beneficiary_id`,7,2)),'-',hex(substr(`tx`.`beneficiary_id`,9,2)),'-',hex(substr(`tx`.`beneficiary_id`,11)))) AS `beneficiary_id`, `tx`.`beneficiary_type` AS `beneficiary_type`, `tx`.`reference_value` AS `reference_value`, lcase(concat(hex(substr(`tx`.`reference_id`,1,4)),'-',hex(substr(`tx`.`reference_id`,5,2)),'-',hex(substr(`tx`.`reference_id`,7,2)),'-',hex(substr(`tx`.`reference_id`,9,2)),'-',hex(substr(`tx`.`reference_id`,11)))) AS `reference_id`, `tx`.`total_minor` AS `total_minor`, `tx`.`currency` AS `currency`, `tx`.`status` AS `status`, `tx`.`created_at` AS `created_at`, (select group_concat(`ci`.`item_name` order by `ci`.`item_name` ASC separator ', ') from (`transaction_lines` `tl` join `catalog_items` `ci` on(`ci`.`catalog_item_id` = `tl`.`catalog_item_id`)) where `tl`.`tx_id` = `tx`.`tx_id`) AS `services` FROM `transactions` AS `tx` WHERE `tx`.`tx_type` = 'DEBIT' ;

